using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    // ───────────────────── ChargeAsync – happy path ─────────────────────

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsNonEmptyChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
    }

    // ───────────────────── ChargeAsync – invalid input ─────────────────────

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(string.Empty, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_WhitespaceToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync("   ", 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid_visa", 0m));
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ThrowsArgumentOutOfRangeException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid_visa", -5.00m));
    }

    // ───────────────────── ChargeAsync – declined card ─────────────────────

    [TestMethod]
    public async Task ChargeAsync_DeclinedToken_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 10.00m);

        Assert.IsFalse(result.Success);
    }

    // ───────────────────── RefundAsync – happy path ─────────────────────

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsNonEmptyRefundId()
    {
        var result = await _gateway.RefundAsync("ch_valid_123");

        Assert.IsFalse(string.IsNullOrWhiteSpace(result.RefundId));
    }

    // ───────────────────── RefundAsync – invalid input ─────────────────────

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(string.Empty));
    }

    [TestMethod]
    public async Task RefundAsync_WhitespaceChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync("   "));
    }

    // ───────────────────── RefundAsync – unknown charge ─────────────────────

    [TestMethod]
    public async Task RefundAsync_UnknownChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    // ───────────────────── Idempotency / uniqueness ─────────────────────

    [TestMethod]
    public async Task ChargeAsync_CalledTwice_ReturnsDifferentChargeIds()
    {
        var first = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);
        var second = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);

        Assert.AreNotEqual(first.ChargeId, second.ChargeId);
    }
}

